<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Conway's Game of Life</title>
<style>
  :root {
    --bg: #0d1117;
    --panel: #161b22;
    --accent: #58a6ff;
    --accent-hover: #79c0ff;
    --cell: #3fb950;
    --grid-line: #21262d;
    --text: #c9d1d9;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    padding: 0;
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 18px;
  }
  h1 {
    margin: 0;
    font-size: 1.6rem;
    letter-spacing: 0.5px;
    color: var(--accent);
    text-shadow: 0 0 12px rgba(88,166,255,0.4);
  }
  #life {
    background: var(--panel);
    border: 2px solid var(--grid-line);
    border-radius: 10px;
    box-shadow: 0 8px 30px rgba(0,0,0,0.5);
    cursor: crosshair;
    touch-action: none;
    width: 480px;
    height: 480px;
    max-width: 92vw;
    max-height: 92vw;
  }
  .controls {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    justify-content: center;
  }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid var(--grid-line);
    padding: 10px 16px;
    border-radius: 8px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: all 0.15s ease;
    font-weight: 600;
  }
  button:hover {
    border-color: var(--accent);
    color: var(--accent-hover);
    transform: translateY(-1px);
  }
  button:active {
    transform: translateY(1px);
  }
  #play.playing {
    background: var(--accent);
    color: #0d1117;
    border-color: var(--accent);
  }
  .hint {
    font-size: 0.8rem;
    opacity: 0.6;
    margin-top: -6px;
  }
</style>
</head>
<body>
  <h1>Conway's Game of Life</h1>
  <canvas id="life" width="480" height="480"></canvas>
  <div class="controls">
    <button id="step">Step</button>
    <button id="play">Play</button>
    <button id="random">Random</button>
    <button id="clear">Clear</button>
  </div>
  <div class="hint">Click or drag on the grid to paint cells alive / dead</div>

<script>
(function () {
  const W = 48;
  const H = 48;
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  const cssSize = 480;
  const cellPx = cssSize / W;

  // grid state: 0 or 1
  let grid = new Uint8Array(W * H);
  let next = new Uint8Array(W * H);

  function idx(x, y) { return y * W + x; }

  function get(x, y) {
    if (x < 0 || y < 0 || x >= W || y >= H) return 0;
    return grid[idx(x, y)];
  }

  function set(x, y, v) {
    if (x < 0 || y < 0 || x >= W || y >= H) return;
    grid[idx(x, y)] = v ? 1 : 0;
    draw();
  }

  function clear() {
    grid.fill(0);
    draw();
  }

  function step() {
    // Compute next generation simultaneously from current grid
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        let n = 0;
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            n += get(x + dx, y + dy);
          }
        }
        const alive = grid[idx(x, y)];
        let nextAlive = 0;
        if (alive) {
          if (n === 2 || n === 3) nextAlive = 1;
        } else {
          if (n === 3) nextAlive = 1;
        }
        next[idx(x, y)] = nextAlive;
      }
    }
    // Apply all at once
    const tmp = grid;
    grid = next;
    next = tmp;
    draw();
  }

  function draw() {
    ctx.fillStyle = '#161b22';
    ctx.fillRect(0, 0, cssSize, cssSize);

    // grid lines
    ctx.strokeStyle = '#21262d';
    ctx.lineWidth = 1;
    for (let i = 0; i <= W; i++) {
      ctx.beginPath();
      ctx.moveTo(i * cellPx, 0);
      ctx.lineTo(i * cellPx, cssSize);
      ctx.stroke();
    }
    for (let j = 0; j <= H; j++) {
      ctx.beginPath();
      ctx.moveTo(0, j * cellPx);
      ctx.lineTo(cssSize, j * cellPx);
      ctx.stroke();
    }

    // live cells
    ctx.fillStyle = '#3fb950';
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[idx(x, y)]) {
          ctx.fillRect(x * cellPx + 1, y * cellPx + 1, cellPx - 2, cellPx - 2);
        }
      }
    }
  }

  // Painting
  let painting = false;
  let paintValue = 1;

  function cellFromEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const px = (e.clientX - rect.left) * (cssSize / rect.width);
    const py = (e.clientY - rect.top) * (cssSize / rect.height);
    const x = Math.floor(px / cellPx);
    const y = Math.floor(py / cellPx);
    return { x, y };
  }

  canvas.addEventListener('pointerdown', (e) => {
    const { x, y } = cellFromEvent(e);
    if (x < 0 || y < 0 || x >= W || y >= H) return;
    painting = true;
    paintValue = grid[idx(x, y)] ? 0 : 1;
    set(x, y, paintValue);
    canvas.setPointerCapture(e.pointerId);
  });

  canvas.addEventListener('pointermove', (e) => {
    if (!painting) return;
    const { x, y } = cellFromEvent(e);
    set(x, y, paintValue);
  });

  canvas.addEventListener('pointerup', () => { painting = false; });
  canvas.addEventListener('pointercancel', () => { painting = false; });

  // Controls
  document.getElementById('step').addEventListener('click', () => step());

  let timer = null;
  const playBtn = document.getElementById('play');
  playBtn.addEventListener('click', () => {
    if (timer) {
      clearInterval(timer);
      timer = null;
      playBtn.textContent = 'Play';
      playBtn.classList.remove('playing');
    } else {
      timer = setInterval(step, 120);
      playBtn.textContent = 'Pause';
      playBtn.classList.add('playing');
    }
  });

  document.getElementById('random').addEventListener('click', () => {
    for (let i = 0; i < grid.length; i++) {
      grid[i] = Math.random() < 0.28 ? 1 : 0;
    }
    draw();
  });

  document.getElementById('clear').addEventListener('click', () => clear());

  // Public API
  window.life = {
    w: W,
    h: H,
    get: get,
    set: set,
    step: step,
    clear: clear
  };

  // initial draw
  draw();
})();
</script>
</body>
</html>
